package com.leapscholar.app.course.listing.domain

import com.leapscholar.app.course.data.dto.CourseSpecificFilter
import com.leapscholar.app.course.data.dto.CoursesFilter
import com.leapscholar.app.explore.data.FilterRequestDto
import com.leapscholar.app.explore.data.SortCourses


enum class CourseScreen{
  SHORTLIST,INTERESTED,BOOKMARKS,EXPLORE,COLLEGE,SUMMARY
}

sealed class GetCourseRequest(val screen : CourseScreen) {
  abstract fun toQuery(): ICourseQuery

  data class Shortlist(
    var filter: List<CourseSpecificFilter> = emptyList(),
    var sortBy: SortCourses
  ) : GetCourseRequest(CourseScreen.SHORTLIST) {
      override fun toQuery(): CourseQuery {
          return CourseQuery(
              filter = CoursesFilter.SHORTLIST,
              courseSpecificFilter = filter.takeIf { it.isNotEmpty() },
              sortBy = sortBy
          )
      }
  }

  object Interested : GetCourseRequest(CourseScreen.INTERESTED) {
    override fun toQuery(): CourseQuery {
      return CourseQuery(
        filter = CoursesFilter.INTERESTED
      )
    }
  }

    class Preferred(courseScreen: CourseScreen) : GetCourseRequest(courseScreen) {
        override fun toQuery(): ICourseQuery {
            return CourseQuery(
                filter = CoursesFilter.STUDENT_PREFERRED
            )
        }
    }


    object SummaryPage: GetCourseRequest(CourseScreen.SUMMARY){
        override fun toQuery(): CourseQuery {
            return CourseQuery(
                filter = CoursesFilter.SHORTLIST,
                sortBy = SortCourses.BEST_MATCH
            )
        }
    }



  data class Explore(
    val courseCategory: String,
    val filter: FilterRequestDto? = null,
    val pageIndex: Int
  ) : GetCourseRequest(CourseScreen.EXPLORE) {
    override fun toQuery(): ExploreCourseQuery {
      return ExploreCourseQuery(
        pageIndex = pageIndex,
        courseCategory = courseCategory,
        selectedCourseFilter = filter
      )
    }
  }
}
