/// CourseDisplay Use Case
/// ----------------------
/// Purpose:
/// - Provides a reusable, embeddable use case to render and manage "Courses" on any screen/page.
/// - Designed to plug directly into existing feature use cases so actions, state, and UI live in one place.
///
/// What it does:
/// - Fetches courses (local cache, remote API, or injected repository).
/// - Exposes a stable state model (loading, content, error) for rendering.
/// - Handles user actions
/// - Supports pagination and empty states out of the box.
///
/// Where to use:
/// - Integrate into any page or parent use case to show courses inline or as a dedicated section.
/// - Compose with your feature’s existing action handler to keep all behavior unified.
///
/// Integration pattern:
/// - Inject dependencies (repository, analytics, schedulers) rather than hardcoding them.
/// - Observe state as a single source of truth (e.g., SwiftUI/Combine or Kotlin Flow).
/// - Forward user actions from UI to this use case; handle side-effects here for consistency.
///
/// Guarantees:
/// - No UI assumptions: pure domain/state with well-defined outputs.
/// - Deterministic state transitions and idempotent actions.
/// - Safe to re-use across multiple screens without shared mutable state.
///
/// Notes:
/// - Keep configuration (filters/sorting) explicit and immutable for reproducible results.
/// - If you add new actions, document the state transition and side-effects here.

class CourseListUseCaseV2 @Inject constructor(
    private val getCourseUseCase: GetCourseUseCase,
    private val abEngineRepo: AbEngineRepo,
    private val addToShortlistCourseCardAction: AddToShortlistCourseCardAction,
    private val feedbackCourseCardAction: PostFeedbackCourseCardAction
) {
    private val _courses: MutableStateFlow<List<CourseCardUi>?> =
        MutableStateFlow(null)

    val courses: StateFlow<List<CourseCardUi>?>
        get() = _courses

    suspend fun get(getCourseRequest: GetCourseRequest) {
        val result = getCourseUseCase(getCourseRequest)
        result?.getShortlistCourses().apply {
            _courses.value = convertToCourseCardUi(
                getCourseRequest.screen, this?.courses ?: emptyList()
            )
        } ?: run {
            _courses.value = emptyList()
        }
    }

    fun getCopyFromCmsAndListForShortlist(courseList: List<CourseCard>) = flow {
        val userId = UserDataUtils.getUserLeapId()
        combine(
            abEngineRepo.getAbTest(
                abTestId = Statics.SHORTLIST_CARD_CTA,
                data = AbTestPost(guid = userId.toLong(), preUserId = userId.toLong())
            ),
            abEngineRepo.getCmsCopyMap(Statics.SHORTLIST_CARD_CTA)
        ) { variant, copyMap ->
            val cta = copyMap?.get(variant) ?: "View Details"
            return@combine cta
        }.collect { value ->
            val result = courseList.map {
                CourseCardUi.ShortlistCourse(it, cmsCopy = value)
            }
            emit(result)
        }
    }

    private suspend fun convertToCourseCardUi(
        courseScreen: CourseScreen, courseList: List<CourseCard>
    ): List<CourseCardUi> {
        return when (courseScreen) {
            CourseScreen.SHORTLIST -> {
                if(courseList.isEmpty()){
                    return emptyList()
                }
                return getCopyFromCmsAndListForShortlist(courseList).first()
            }
            CourseScreen.INTERESTED -> {
                courseList
                    .filter { it.feedback == Feedback.POSITIVE }
                    .map {
                        CourseCardUi.InterestedCourse(it)
                    }
            }

            CourseScreen.BOOKMARKS ->{
                courseList.map {
                    CourseCardUi.PreferredCourse(it)
                }
            }

            CourseScreen.SUMMARY -> {
                courseList.map {
                    CourseCardUi.SummaryCourse(it)
                } + listOf<CourseCardUi>(CourseCardUi.SummaryCourseEndCard)
            }

            else -> {
                emptyList()
            }
        }
    }

    suspend fun addOrRemoveShortlist(
        screen: CourseScreen,
        addToShortlist: Boolean,
        courseId: Long
    ) {
        addToShortlistCourseCardAction(
            courseAdditionSource = CourseAdditionSource.COURSE_FINDER_FILTERS,
            addToShortlist = getAdditionAction(addToShortlist = addToShortlist),
            courseId
        ).collect {
            _courses.update {
                it?.map { value ->
                    if(value is CourseCardUi.CourseBox && value.courseCard.courseId == courseId){
                        val i = value.courseCard.copy(
                            bookmarked = addToShortlist,
                            shortlisted = addToShortlist
                        )
                        val result = returnCourseCardUIBasedOnScreen(
                            screen = screen,
                            prevValue = value,
                            courseData = i
                        )
                        result
                    } else{
                        return@map value
                    }
                }
            }
        }
    }

    private fun returnCourseCardUIBasedOnScreen(
        screen: CourseScreen,
        prevValue : CourseCardUi,
        courseData: CourseCard
    ) : CourseCardUi{
        return when(screen){
            CourseScreen.SHORTLIST -> {
                if(prevValue is CourseCardUi.ShortlistCourse) {
                    CourseCardUi.ShortlistCourse(courseData, cmsCopy = prevValue.cmsCopy)
                } else{
                    CourseCardUi.ShortlistCourse(courseData,)
                }
            }

            CourseScreen.INTERESTED -> {
                CourseCardUi.InterestedCourse(courseData)
            }

            CourseScreen.BOOKMARKS ->{
                CourseCardUi.PreferredCourse(courseData)
            }

            CourseScreen.SUMMARY -> {
                CourseCardUi.SummaryCourse(courseData)
            }
            else -> {
                CourseCardUi.ShortlistCourse(courseData)
            }
        }
    }
    private fun getAdditionAction(addToShortlist: Boolean): AddRemoveShortlistCourseAction {
        return if(UserDataUtils.getIsShortlistedUserOrMore()){
            if (addToShortlist) AddRemoveShortlistCourseAction.ADD_SHORTLIST else AddRemoveShortlistCourseAction.REMOVE_SHORTLIST
        } else{
            if (addToShortlist) AddRemoveShortlistCourseAction.ADD_TO_STUDENT_LIST else AddRemoveShortlistCourseAction.REMOVE_FROM_STUDENT_LIST
        }
    }

    suspend fun feedback(
        screen: CourseScreen,
        feedback: Feedback,
        courseId: Long
    ) {
        feedbackCourseCardAction(feedback = feedback, courseId).collect {
            _courses.update {
                it?.map { value ->
                    if(value is CourseCardUi.CourseBox && value.courseCard.courseId == courseId){
                        val i = value.courseCard.copy(
                            feedback = feedback
                        )

                        returnCourseCardUIBasedOnScreen(
                            screen = screen,
                            prevValue = value ,
                            courseData = i
                        )
                    } else{
                        return@map value
                    }
                }
            }
        }
    }
}

