import javax.inject.Inject
import kotlinx.coroutines.flow.catch
import kotlinx.coroutines.flow.collect
import kotlinx.coroutines.flow.combine

class UserLoginStateBuilder @Inject constructor(
    private val studentRepository: StudentRepository,
    val marketingRepository: MarketingRepository,
    private val loginFlowResolver: LoginFlowResolver
) {

    suspend fun getUserCurrentLoginState(): LeapLoginState {
        var loginState: LeapLoginState = LeapLoginState.NONE
        combine(
            studentRepository.getStudentEligibility(),
            studentRepository.getStudentStage(),
            studentRepository.getUserDetail(),
            studentRepository.getLoginConfig(),
            MarketingClient.registerUserWithMarketer(
                marketingRepository, BuildConfig.APPLICATION_ID
            )
        ) { eligibility, stage, userDetail, config, _ ->
            if (stage == null || userDetail == null || config == null) {
                loginState = LeapLoginState.ERROR
            } else {
                setAppInstalled()

                val loginFlowConfig = loginFlowResolver.resolve()
                val acceleratedConfig = if (UserDataUtils.isAcceleratedUser()) {
                    studentRepository.getAcceleratedConfig()
                } else {
                    null
                }
                loginState = loginFlowConfig.resolveLoginState(
                    eligibility = eligibility,
                    userDetail = userDetail,
                    acceleratedConfig = acceleratedConfig
                )
            }

        }.catch {
            loginState = LeapLoginState.ERROR
        }.collect {}

        return loginState
    }

    private suspend fun setAppInstalled() {
        studentRepository.isAppInstalled().collect { _ ->
        }
    }

}

enum class LeapLoginState {
    QE_FORM,
    TOFU_PREFERENCE,
    TOFU_TARGET,
    STUDENT_DETAILS,
    ACCELERATED_PREFERENCES,
    ACCELERATED_DEGREE,
    ERROR,
    DASHBOARD,
