import com.leapscholar.app.tofu.data.model.TofuFragmentClassifier
import com.leapscholar.app.utils.ActivityTransitionHelper
import com.leapscholar.app.utils.ApplicationUtils
import com.leapscholar.app.utils.SegmentAnalytics
import com.leapscholar.app.utils.data.AuthDataUtils
import com.leapscholar.app.utils.data.UserDataUtils
import com.leapscholar.app.webengage.WebEngageAppConfig
import javax.inject.Inject
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch

class UserLoginStateHandler @Inject constructor(
    val studentRepository: StudentRepository
) {
    private  val webEngageAppConfig = WebEngageAppConfig()
    fun handleState(state: LeapLoginState,activity: Activity){
        setupModules()
        setSegmentUser()
        webEngageSetup()
        redirectToActivity(state, activity)
    }

    private fun webEngageSetup(){
        if (!AuthDataUtils.isWebEngageLoggedIn()) {
            CoroutineScope(Dispatchers.IO).launch {
                studentRepository.getUserDetail().collect { data ->
                    webEngageAppConfig.setWebEngageUserProperties(
                        email = data?.email,
                        name = data?.name,
                        phone = data?.phone
                    )
                }
            }
        }
    }

    private fun redirectToActivity(
        state: LeapLoginState,
        activity: Activity
    ) {
        when (state) {
            LeapLoginState.STUDENT_DETAILS -> {
              activity.startActivity(Intent(activity, TofuFormActivity::class.java).apply {
                flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
                putExtra("TOFU_PAGE", TofuFragmentClassifier.EmailAndNamePage)
              })
            }
            LeapLoginState.QE_FORM -> {
                activity.startActivity(Intent(activity, TofuFormActivity::class.java).apply {
                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
                })
            }

            LeapLoginState.ACCELERATED_PREFERENCES,
            LeapLoginState.ACCELERATED_DEGREE -> {
                val destination = if (state == LeapLoginState.ACCELERATED_PREFERENCES) {
                    ProfileSetupActivity::class.java
                } else {
                    PathSelectionActivity::class.java
                }
                activity.startActivity(Intent(activity, destination).apply {
                    flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
                })
            }

            LeapLoginState.TOFU_PREFERENCE, LeapLoginState.TOFU_TARGET -> {
              activity.startActivity(Intent(activity, TofuFormActivity::class.java).apply {
                flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
                putExtra("TOFU_PAGE", TofuFragmentClassifier.StudyPreferences(
                  dto = StudyPreferenceRequestDto()
                ))
              })
            }

            LeapLoginState.ERROR -> {
                Toast.makeText(activity, "Something went wrong", Toast.LENGTH_SHORT).show()
            }

            LeapLoginState.DASHBOARD -> {
                ActivityTransitionHelper.toMainFragmentActivity(activity, null)
            }

            LeapLoginState.NONE -> {

            }
        }
    }

    private fun setupModules(){
        ParikshaWizard(ApplicationUtils.application)
            .addAuthToken(AuthDataUtils.getToken() ?: "")
            .addUserId(UserDataUtils.getUserLeapId().toLong())
            .isLsAppUser(true)

        BolBachchanWizard(ApplicationUtils.application)
            .addAuthToken(AuthDataUtils.getToken() ?: "")
            .addUserId(UserDataUtils.getUserLeapId().toLong())
            .isLsAppUser(true)
    }


    private fun setSegmentUser() {
        if (!AuthDataUtils.isSegmentLogin()) {
            SegmentAnalytics.setUser(UserDataUtils.getUserLeapId())
        }
    }
}

