import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.map


class ShortlistUseCase @Inject constructor(
    private val shortlistCourseListUseCase: CourseListUseCaseV2,
    recommendedCourseListUseCaseProvider: Provider<CourseListUseCaseV2>,
    private val filterAndSortManager: ShortlistFilterAndSortManager,
    private val videoMessageRepo: VideoMessageRepo,
) {
    private val recommendedCourseListUseCase = recommendedCourseListUseCaseProvider.get()


    private val _feedbackStatus = MutableStateFlow(UserDataUtils.getOverallFeedbackStatus())
    val feedbackStatus: StateFlow<Boolean> = _feedbackStatus.asStateFlow()

    val courses: Flow<CourseListUiData>
        get() = combine(
            shortlistCourseListUseCase.courses,
            videoMessageRepo.getVideoUrl(),
            feedbackStatus,
            selectedFilters,
            selectedSort
        ) { courseList, videoUrl, feedbackStatusValue, filters, sort ->
            courseList?.let {
                if (courseList.isEmpty()) {
                    if (filters.isEmpty()) {
                        CourseListUiData.Empty
                    } else {
                        CourseListUiData.FilterEmpty
                    }
                } else {
                    var r = courseList
                    if (!feedbackStatusValue) {
                        r = courseList + CourseCardUi.Feedback
                    }

                    val hasFilters = filters.isNotEmpty()
                    val hasSort = sort != SortCourses.BEST_MATCH
                    val shouldShowIndicator = hasFilters || hasSort

                    val courseCount = courseList.count { it is CourseCardUi.CourseBox }

                    val finalList = if (shouldShowIndicator) {

                        listOf(
                            CourseCardUi.ShortlistFilterSortIndicator(
                                courseCount = courseCount,
                                filterState =  ShortlistFilterState(
                                    filters = filters,
                                    sort = sort
                                )
                            )
                        ) + r + CourseCardUi.ShortlistExploreCard

                    } else {

                        r + CourseCardUi.ShortlistExploreCard

                    }

                    CourseListUiData.Success(data = finalList, videoUrl = videoUrl)
                }
            } ?: run {
                CourseListUiData.Loading
            }
        }

    val recommendedCourses: Flow<CourseListUiData>
        get() = recommendedCourseListUseCase.courses.map { courseList ->
            courseList?.let {
                if (it.isEmpty()) {
                    CourseListUiData.Empty
                } else {
                    CourseListUiData.Success(data = it)
                }
            } ?: CourseListUiData.Loading
        }


    val selectedFilters: StateFlow<List<CourseSpecificFilter>>
        get() = filterAndSortManager.filter

    val selectedSort: StateFlow<SortCourses>
        get() = filterAndSortManager.sort

    suspend fun getCourses(fetchRecommended: Boolean) {
        getShortlist()
        if (fetchRecommended) {
            getRecommended()
        }
    }

    private fun getShortlistCourseRequest(): GetCourseRequest {
        return if (UserDataUtils.getIsTofuExtended()) {
            GetCourseRequest.Preferred(CourseScreen.BOOKMARKS)
        } else {
            GetCourseRequest.Shortlist(
                filter = filterAndSortManager.filter.value,
                sortBy = filterAndSortManager.sort.value
            )
        }
    }

    private fun getAthenaCourseRequest(): GetCourseRequest {
        return GetCourseRequest.Athena
    }

    suspend fun getShortlist() {
        shortlistCourseListUseCase.get(getShortlistCourseRequest())
    }

    suspend fun getRecommended() {
        recommendedCourseListUseCase.get(getAthenaCourseRequest())
    }

    suspend fun actionFeedback(feedback: Feedback, courseId: Long) {
        shortlistCourseListUseCase.feedback(CourseScreen.SHORTLIST, feedback, courseId)
    }

    suspend fun actionShortlist(addToShortlist: Boolean, courseId: Long) {
        shortlistCourseListUseCase.addOrRemoveShortlist(
            CourseScreen.BOOKMARKS, addToShortlist, courseId
        )
    }

    suspend fun filterAndSort(filterState: ShortlistFilterState) {
        filterAndSortManager.clearFilters()
        filterAndSortManager.addFilter(filterState.filters)
        filterAndSortManager.sortBy(filterState.sort)
        getShortlist()
    }

    fun updateFeedbackStatus(status: Boolean) {
        _feedbackStatus.value = status
        UserDataUtils.setOverallFeedbackStatus(status)
    }
}

