import com.leapscholar.app.utils.showCustomToast
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.flow.collectLatest
import kotlinx.coroutines.launch


@OptIn(ExperimentalFoundationApi::class, ExperimentalMaterial3Api::class)
@Composable
fun ShortlistScreen(
    goToExplore: () -> Unit = {}
) {
    val context = LocalContext.current
    val shortlistViewModel: ShortlistViewModel = daggerActivityViewModel<ShortlistViewModel>()
    val filterUiState by shortlistViewModel.filterState.collectAsStateWithLifecycle()
    val coursesState = shortlistViewModel.courses.collectAsStateWithLifecycle()
    val recommendedState = shortlistViewModel.recommendedCourses.collectAsStateWithLifecycle()
    val selectedTab by shortlistViewModel.selectedTab.collectAsStateWithLifecycle()
    var showPiPPlayer by remember { mutableStateOf(false) }
    var showFilterFab by remember { mutableStateOf(true) }
    val sheetState = rememberModalBottomSheetState(
        skipPartiallyExpanded = true
    )
    val coroutineScope = rememberCoroutineScope()
    val snackBarHostState = remember { SnackbarHostState() }
    val bottomSheetState by shortlistViewModel.bottomSheetState.collectAsState()

    var selectedCounsellor by remember { mutableStateOf<UserDashboardLeapPartnerModel?>(null) }
    val bottomSheetContent =
        remember { mutableStateOf<BottomSheetContent>(BottomSheetContent.EMPTY) }

    val viewConfig = shortlistViewModel.viewConfig
    val tabs = viewConfig.tabs
    val screenTitle = viewConfig.screenTitle
    val effectiveSelectedTab = if (tabs.size == 1) {
        ShortlistTabKey.SHORTLISTED
    } else {
        selectedTab
    }
    val refreshSelectedTabData: () -> Unit = {
        when (effectiveSelectedTab) {
            ShortlistTabKey.RECOMMENDED -> shortlistViewModel.getRecommended()
            ShortlistTabKey.SHORTLISTED -> shortlistViewModel.getCourses()
        }
    }



    // Launcher for InterestedCoursesActivity to refresh count on return
    val interestedActivityLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.StartActivityForResult()
    ) { _ ->
        coroutineScope.launch {
            refreshSelectedTabData()
        }
    }

    // Launcher for Feedback
    val feedbackLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            shortlistViewModel.updateFeedbackStatus(true)
        }
    }

    LaunchedEffect(Unit) {
        shortlistViewModel.launchFeedback.collect {
            if(it && !UserDataUtils.getOverallFeedbackStatus()){
                feedbackLauncher.launch(Intent(context, FeedbackActivity::class.java).apply {
                    this.putExtra(Statics.FEEDBACK_PAGE_TYPE, FeedbackUiType.ShortlistFeedback)
                })
            }else{
                context.showCustomToast("Feedback already submitted")
            }
        }
    }

    val core by shortlistViewModel.corePlayerUiState.collectAsState()
    val reattachVideo by shortlistViewModel.reattachVideo.collectAsState()

    val launcherForExpandedVideo = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.StartActivityForResult(), onResult = {
            shortlistViewModel.triggerReattach()
        })

    LaunchedEffect(core.playback) {
        when (core.playback) {
            PlaybackStates.Playing -> {
                showPiPPlayer = true
                showFilterFab = false
            }

            PlaybackStates.Finished -> {
                showPiPPlayer = false
                showFilterFab = true
            }

            PlaybackStates.Paused -> {

            }
        }
    }

    BackHandler {
        if (sheetState.isVisible) {
            coroutineScope.hideSheet(sheetState)
        } else if (!UserDataUtils.getOverallFeedbackStatus()) {
            context.startActivity(Intent(context, FeedbackActivity::class.java).apply {
                putExtra(Statics.FEEDBACK_PAGE_TYPE, FeedbackUiType.ShortlistFeedback)
            })
        }
    }

    DisposableEffect(Unit) { onDispose { shortlistViewModel.showBottom(identifier = ShortlistBottomSheetIdentifier.None) }}


    var showBars by remember { mutableStateOf(true) }

    LaunchedEffect(Unit) {
        LeapChromeController.events.collectLatest { event ->
            when(event){
                is LeapUIEvent.ScrollUp->{
                    showBars = true
                    showFilterFab = !showPiPPlayer
                }
                is LeapUIEvent.ScrollDown->{
                    showBars = false
                    showFilterFab = false
                }
            }
        }
    }

    LaunchedEffect(Unit) {
        shortlistViewModel.trackPageVisited()
    }

    LaunchedEffect(Unit) {
        refreshSelectedTabData()
    }

    LaunchedEffect(Unit) {
        shortlistViewModel.goToExplore.collectLatest {
            goToExplore()
        }
    }

    LaunchedEffect(bottomSheetState) {
        when (bottomSheetState) {
            is ShortlistBottomSheetIdentifier.None -> {
                if (sheetState.isVisible) {
                    sheetState.hide()
                    sheetState.hide()
                }
            }
            else -> {
                if (!sheetState.isVisible) {
                    sheetState.show()
                }
            }
        }
    }

    Box(modifier = Modifier.fillMaxSize()) {
        Scaffold(
            topBar = {
                AnimatedVisibility(
                    modifier = Modifier.background(color  = LeapColorProvider.provideColor(
                        BgColorToken.BasicWhite)),
                    visible = showBars,
                    enter = fadeIn(
                        animationSpec = tween(300, easing = FastOutSlowInEasing)
                    ) + slideInVertically(
                        initialOffsetY = { -it / 3 },
                        animationSpec = tween(300, easing = FastOutSlowInEasing)
                    ),
                    exit = fadeOut(
                        animationSpec = tween(200, easing = FastOutLinearInEasing)
                    ) + slideOutVertically(
                        targetOffsetY = { -it / 3 },
                        animationSpec = tween(200, easing = FastOutLinearInEasing)
                    )
                ) {
                    LeapToolBar(
                        title = screenTitle
                    )
                }
            },
            floatingActionButton = {
                if (viewConfig.showFilterFab &&
                    effectiveSelectedTab == ShortlistTabKey.SHORTLISTED &&
                    (coursesState.value is CourseListUiData.Success)
                ) {
                    val isStartApplyingSectionVisible = when (val uiData = coursesState.value) {
                        is CourseListUiData.Success -> {
                            val shortlist = uiData.data.filterIsInstance<CourseCardUi.ShortlistCourse>()
                            val likedCourses = shortlist.filter { it.courseCard.feedback == Feedback.POSITIVE }
                            shortlist.isNotEmpty() &&
                                likedCourses.isNotEmpty() &&
                                showBars &&
                                viewConfig.bottomBarConfig != null
                        }
                        else -> false
                    }
                    AnimatedVisibility(
                        visible = showFilterFab,
                        enter = fadeIn(tween(300, easing = FastOutSlowInEasing)) +
                            slideInVertically(
                                initialOffsetY = { it / 2 },
                                animationSpec = tween(300)
                            ),
                        exit = fadeOut(tween(200)) +
                            slideOutVertically(
                                targetOffsetY = { it / 2 },
                                animationSpec = tween(200)
                            )
                    ) {
                        val fabBottomPadding by animateDpAsState(
                            targetValue = if (isStartApplyingSectionVisible) 0.dp else LeapSpacing.X2L.dp,
                            animationSpec = tween(350, easing = FastOutSlowInEasing)
                        )
                        if ((coursesState.value as CourseListUiData.Success).data.isNotEmpty()) {
                            Box(
                                modifier = Modifier.padding(
                                    bottom = fabBottomPadding
                                )
                            ) {
                                ShortlistFilterFAB(
                                    filterCount = filterUiState.filters.size +
                                        if (filterUiState.sort != SortCourses.BEST_MATCH) 1 else 0,
                                    onClick = {
                                        shortlistViewModel.filterClick()
                                        shortlistViewModel.showBottom(ShortlistBottomSheetIdentifier.FilterBottomSheet)
                                    },
                                )
                            }
                        }
                    }
                }
            },
            bottomBar = {
                when (val uiData = coursesState.value) {
                    is CourseListUiData.Success -> {
                        val bottomBarConfig = viewConfig.bottomBarConfig
                        val isShortlistedTab = effectiveSelectedTab == ShortlistTabKey.SHORTLISTED
                        val showStartApplyingSection = remember(
                            coursesState.value,
                            showBars,
                            isShortlistedTab,
                            bottomBarConfig
                        ) {
                            val uiData = coursesState.value
                            if (uiData is CourseListUiData.Success) {
                                val shortlist =
                                    uiData.data.filterIsInstance<CourseCardUi.ShortlistCourse>()
                                val likedCourses =
                                    shortlist.filter { it.courseCard.feedback == Feedback.POSITIVE }
                                shortlist.isNotEmpty() &&
                                    likedCourses.isNotEmpty() &&
                                    showBars &&
                                    isShortlistedTab &&
                                    bottomBarConfig != null
                            } else false
                        }
                        AnimatedVisibility(
                            visible = showStartApplyingSection,
                            enter = fadeIn(tween(100, easing = FastOutSlowInEasing)),
                            exit = fadeOut(tween(100))
                        ) {
                        Box(modifier = Modifier.fillMaxWidth()) {
                            val shortlist = uiData.data.filterIsInstance<CourseCardUi.ShortlistCourse>()
                            if (shortlist.isNotEmpty()) {
                                val likedCourses = shortlist.filter {
                                    it.courseCard.feedback == Feedback.POSITIVE
                                }
                                if (likedCourses.isNotEmpty()) {
                                    StartApplyingSection(
                                        coursesLiked = likedCourses.size,
                                        ctaText = bottomBarConfig?.ctaText.orEmpty(),
                                        onApplyNowClick = {
                                            when (bottomBarConfig?.action) {
                                                ShortlistBottomBarAction.StartApplying -> {
                                                    shortlistViewModel.startApplyClick()
                                                    interestedActivityLauncher.launch(
                                                        Intent(
                                                            context,
                                                            InterestedCoursesActivity::class.java
                                                        )
                                                    )
                                                }

                                                ShortlistBottomBarAction.BookDiscussion -> {
                                                    context.startActivity(
                                                        Intent(context, ScheduledCallActivity::class.java)
                                                    )
                                                }

                                                null -> Unit
                                            }
                                        }
                                    )
                                }
                            }
                            SnackbarHost(hostState = snackBarHostState) { data ->
                                Column(modifier = Modifier.padding(bottom = 80.dp)) {
                                    SuccessSnackBar(text = data.visuals.message)
                                }
                            }
                        }
                    }
                    }

                    else -> {}
                }
            },
            containerColor = Color.White
        ) { paddingValues ->
            val animatedTopPadding by animateDpAsState(
                targetValue = if (showBars) paddingValues.calculateTopPadding() else 0.dp,
                animationSpec = tween(300, easing = FastOutSlowInEasing)
            )
            val shortlistedListState = rememberLazyListState()
            val recommendedListState = rememberLazyListState()
            if (effectiveSelectedTab == ShortlistTabKey.SHORTLISTED) {
                shortlistedListState.emitScrollEvents(LeapUIEventCourseScreen.SHORTLIST)
            }

            Box(
                modifier = Modifier
                    .background(LeapColorProvider.provideColor(BgColorToken.NeutralDefault))
                    .fillMaxSize()
                    .padding(
                        top = animatedTopPadding,
                        bottom = paddingValues.calculateBottomPadding(),
                        start = paddingValues.calculateStartPadding(LayoutDirection.Ltr),
                        end = paddingValues.calculateEndPadding(LayoutDirection.Ltr)
                    )
            ) {
                Column(modifier = Modifier.fillMaxSize()) {
                    if (tabs.size > 1) {
                        LeapTabs(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(
                                    horizontal = LeapSpacing.XL.dp,
                                    vertical = LeapSpacing.M.dp
                                ),
                            config = tabs.map {
                                LeapTabConfig(
                                    text = it.displayName,
                                    iconLayout = IconLayout.None
                                )
                            },
                            selectedIndex = tabs.indexOf(effectiveSelectedTab).coerceAtLeast(0),
                            onClick = { index ->
                                shortlistViewModel.onTabSelected(tabs[index])
                            }
                        )
                    }

                    when (effectiveSelectedTab) {
                        ShortlistTabKey.SHORTLISTED -> {
                            when (val uiData = coursesState.value) {
                                is CourseListUiData.Loading -> {
                                    LeapFullScreenLoader()
                                }

                                is CourseListUiData.Success -> {
                                    Box(modifier = Modifier.fillMaxSize()) {
                                        LazyColumn(
                                            modifier = Modifier.fillMaxSize(),
                                            contentPadding = PaddingValues(
                                                bottom = 210.dp,
                                                top = if (viewConfig.showCounsellorCard) 70.dp else 0.dp
                                            ),
                                            state = shortlistedListState
                                        ) {
                                            if (uiData.data.isNotEmpty()) {
                                                item {
                                                    Spacer(modifier = Modifier.height(LeapSpacing.L.dp))
                                                }

                                                items(uiData.data) { courseCardUi ->
                                                    courseCardUi.RenderCourse(
                                                        context = context,
                                                        action = shortlistViewModel
                                                    )
                                                }
                                            }
                                        }

                                        if (viewConfig.showCounsellorCard) {
                                            val counsellorData = shortlistViewModel.getCounsellorData()
                                            Box(modifier = Modifier.padding(bottom = LeapSpacing.XL.dp)) {
                                                StickyCounsellorCard(
                                                    counsellorName = counsellorData?.counsellorName
                                                        ?: "Counsellor",
                                                    counsellorImage = counsellorData?.imageUrl,
                                                    onCallNowClick = {
                                                        actIfConnected(context) {
                                                            shortlistViewModel.callNowClick()
                                                            counsellorData?.let { selectedCounsellor = it }
                                                            if (shortlistViewModel.getCounsellorLockedStatus()) {
                                                                shortlistViewModel.showBottom(
                                                                    ShortlistBottomSheetIdentifier.UpgradeLeapPrimeSheet
                                                                )
                                                            } else {
                                                                shortlistViewModel.showBottom(
                                                                    ShortlistBottomSheetIdentifier.CounsellorOptionsSheet
                                                                )
                                                            }
                                                        }
                                                    },
                                                    onCardClick = {
                                                        shortlistViewModel.counsellorCardClick()
                                                        context.startActivity(
                                                            Intent(
                                                                context,
                                                                CounsellorProfileActivity::class.java
                                                            )
                                                        )
                                                    },
                                                )
                                            }
                                        }

                                        // Floating PiP Video Player
                                        androidx.compose.animation.AnimatedVisibility(
                                            visible = showPiPPlayer,
                                            enter = slideInVertically(
                                                animationSpec = tween(
                                                    durationMillis = 500,
                                                    easing = FastOutSlowInEasing
                                                ),
                                                initialOffsetY = { fullHeight -> fullHeight }
                                            ) + fadeIn(
                                                animationSpec = tween(
                                                    durationMillis = 300,
                                                    easing = FastOutSlowInEasing
                                                )
                                            ),
                                            exit = slideOutVertically(
                                                animationSpec = tween(
                                                    durationMillis = 250,
                                                    easing = FastOutLinearInEasing
                                                ),
                                                targetOffsetY = { fullHeight -> fullHeight }
                                            ) + fadeOut(
                                                animationSpec = tween(
                                                    durationMillis = 250,
                                                    easing = FastOutLinearInEasing
                                                )
                                            )
                                        ) {
                                            uiData.videoUrl?.let {
                                                key(reattachVideo) {
                                                    DraggablePiPVideoPlayer(
                                                        videoUrl = it,
                                                        onExpandClick = {
                                                            shortlistViewModel.pipExpandClick()
                                                            val intent = Intent(
                                                                context,
                                                                VideoMessageActivity::class.java
                                                            ).apply {
                                                                putExtra(Statics.PLAY_VIDEO, true)
                                                            }
                                                            launcherForExpandedVideo.launch(intent)
                                                        },
                                                        onCloseClick = {
                                                            shortlistViewModel.pauseCompletely()
                                                            showPiPPlayer = false
                                                            showFilterFab = true
                                                        },
                                                        modifier = Modifier.zIndex(1f),
                                                        controller = shortlistViewModel
                                                    )
                                                }
                                            }
                                        }
                                    }
                                }

                                is CourseListUiData.Empty -> {
                                    Column(
                                        modifier = Modifier.fillMaxSize(),
                                        verticalArrangement = Arrangement.Center
                                    ) {
                                        EmptyStateCard(
                                            icon = painterResource(R.drawable.empty_shortlist_screen),
                                            title = "Your shortlisted courses will appear here",
                                            subtitle = "Explore courses to add to your shortlist",
                                            buttonText = "Start exploring courses"
                                        ) {
                                            goToExplore.invoke()
                                        }
                                    }
                                }

                                is CourseListUiData.Error -> {
                                    Box(modifier = Modifier.fillMaxSize()) {
                                        LeapErrorPage {
                                            coroutineScope.launch {
                                                refreshSelectedTabData()
                                            }
                                        }
                                    }
                                }

                                is CourseListUiData.FilterEmpty -> {
                                    Column(modifier = Modifier.fillMaxSize()) {
                                        if (viewConfig.showCounsellorCard) {
                                            val counsellorData = shortlistViewModel.getCounsellorData()
                                            StickyCounsellorCard(
                                            StickyCounsellorCard(
                                                counsellorName = counsellorData?.counsellorName ?: "Counsellor",
                                                counsellorImage = counsellorData?.imageUrl,
                                                onCallNowClick = {
                                                    actIfConnected(context) {
                                                        shortlistViewModel.callNowClick()
                                                        counsellorData?.let { selectedCounsellor = it }
                                                        if (shortlistViewModel.getCounsellorLockedStatus()) {
                                                            shortlistViewModel.showBottom(
                                                                ShortlistBottomSheetIdentifier.UpgradeLeapPrimeSheet
                                                            )
                                                        } else {
                                                            shortlistViewModel.showBottom(
                                                                ShortlistBottomSheetIdentifier.CounsellorOptionsSheet
                                                            )
                                                        }
                                                    }
                                                },
                                                onCardClick = {
                                                    shortlistViewModel.counsellorCardClick()
                                                    context.startActivity(
                                                        Intent(context, CounsellorProfileActivity::class.java)
                                                    )
                                                }
                                            )
                                        }

                                        Column(
                                            modifier = Modifier.fillMaxSize(),
                                            verticalArrangement = Arrangement.Center
                                        ) {
                                            EmptyStateCard(
                                                icon = painterResource(R.drawable.empty_filter),
                                                title = "No results were found for applied filters",
                                                subtitle = "Clear your filters or select some other filters to view courses",
                                                buttonText = "Go to Filters"
                                            ) {
                                                shortlistViewModel.showBottom(ShortlistBottomSheetIdentifier.FilterBottomSheet)
                                            }
                                        }
                                    }
                                }
                            }
                        }

                        ShortlistTabKey.RECOMMENDED -> {
                            when (val uiData = recommendedState.value) {
                                is CourseListUiData.Loading -> {
                                    LeapFullScreenLoader()
                                }

                                is CourseListUiData.Success -> {
                                    LazyColumn(
                                        modifier = Modifier.fillMaxSize(),
                                        contentPadding = PaddingValues(bottom = 40.dp),
                                        state = recommendedListState
                                    ) {
                                        item {
                                            Spacer(modifier = Modifier.height(LeapSpacing.L.dp))
                                        }
                                        items(uiData.data) { courseCardUi ->
                                            courseCardUi.RenderCourse(
                                                context = context,
                                                action = shortlistViewModel
                                            )
                                        }
                                    }
                                }

                                is CourseListUiData.Empty -> {
                                    Column(
                                        modifier = Modifier.fillMaxSize(),
                                        verticalArrangement = Arrangement.Center
                                    ) {
                                        EmptyStateCard(
                                            icon = painterResource(R.drawable.empty_shortlist_screen),
                                            title = "We're preparing your recommendations",
                                            subtitle = "Complete your profile so we can suggest the best courses for you",
                                            buttonText = "Complete Profile"
                                        ) {
                                            context.startActivity(Intent(context, TofuFormActivity::class.java))
                                        }
                                    }
                                }

                                is CourseListUiData.Error -> {
                                    Column(
                                        modifier = Modifier.fillMaxSize(),
                                        verticalArrangement = Arrangement.Center
                                    ) {
                                        EmptyStateCard(
                                            icon = painterResource(R.drawable.empty_shortlist_screen),
                                            title = "Something went wrong",
                                            subtitle = "We couldn't load your recommended courses. Please try again.",
                                            buttonText = "Retry"
                                        ) {
                                            shortlistViewModel.getRecommended()
                                        }
                                    }
                                }

                                is CourseListUiData.FilterEmpty -> Unit
                            }
                        }
                    }
                }
            }
        }

        if (bottomSheetState !is ShortlistBottomSheetIdentifier.None || sheetState.isVisible) {
            ModalBottomSheet(
                onDismissRequest = {
                    coroutineScope.launch {
                        sheetState.hide()
                        shortlistViewModel.showBottom(ShortlistBottomSheetIdentifier.None)
                    }
                },
                sheetState = sheetState,
                dragHandle = {
                    BottomSheetDefaults.DragHandle()
                             },
                shape = LeapCornerShape.rounded_xl.shape,
                containerColor = LeapColorProvider.provideColor(BgColorToken.BasicWhite)
            ) {
                ShortlistBottomSheetContent(
                    bottomSheetState = bottomSheetState,
                    filterUiState = filterUiState,
                    sheetState = sheetState,
                    selectedCounsellor = selectedCounsellor,
                    coroutineScope = coroutineScope,
                    viewModel = shortlistViewModel,
                )
            }
        }
    }
}
@OptIn(ExperimentalMaterial3Api::class)
fun CoroutineScope.hideSheet(sheet: SheetState) {
    this.launch { sheet.hide() }
}

