package com.leapscholar.app.shortlist.domain

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import androidx.media3.exoplayer.ExoPlayer
import com.leapscholar.app.course.listing.CourseListingAction
import com.leapscholar.app.dashboard.data.CourseListUiData
import com.leapscholar.app.data.model.UserDashboardLeapPartnerModel
import com.leapscholar.app.data.network.Feedback
import com.leapscholar.app.data.network.UserType
import com.leapscholar.app.explore.data.SortCourses
import com.leapscholar.app.experience.core.ShortlistTabKey
import com.leapscholar.app.experience.core.ShortlistViewConfig
import com.leapscholar.app.helper.CacheHelper
import com.leapscholar.app.shortlist.analytics.ShortlistAnalytics
import com.leapscholar.app.shortlist.data.filters.ShortlistFilterState
import com.leapscholar.app.shortlist.ui.ShortlistBottomSheetIdentifier
import com.leapscholar.app.shortlist.ui.ShortlistEvent
import com.leapscholar.app.shortlist.video.data.CorePlayerState
import com.leapscholar.app.shortlist.video.data.IslVideoControllerInterface
import com.leapscholar.app.shortlist.video.domain.ISLVideoUseCase
import com.leapscholar.app.utils.data.UserDataUtils
import com.leapscholar.app.viewmodel.ioJob
import javax.inject.Inject
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

class ShortlistViewModel @Inject constructor(
   private val shortlist : ShortlistUseCase,
    private val islVideoUseCase: ISLVideoUseCase,
   val analytics: ShortlistAnalytics,
   val viewConfig: ShortlistViewConfig
) : CourseListingAction,ViewModel(),IslVideoControllerInterface{


    val courses: StateFlow<CourseListUiData> =
        shortlist.courses.stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5_000),
            initialValue = CourseListUiData.Loading
        )

    val recommendedCourses: StateFlow<CourseListUiData> =
        shortlist.recommendedCourses.stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5_000),
            initialValue = CourseListUiData.Loading
        )

    private val _selectedTab: MutableStateFlow<ShortlistTabKey> = MutableStateFlow(
        if (viewConfig.tabs.contains(ShortlistTabKey.RECOMMENDED)) {
            ShortlistTabKey.RECOMMENDED
        } else {
            ShortlistTabKey.SHORTLISTED
        }
    )
    val selectedTab: StateFlow<ShortlistTabKey> = _selectedTab.asStateFlow()

    val filterState: StateFlow<ShortlistFilterState> =
        combine(
            shortlist.selectedFilters,
            shortlist.selectedSort
        ) { filters, sort ->
            ShortlistFilterState(
                filters = filters,
                sort = sort
            )
        }.stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5_000),
            initialValue = ShortlistFilterState(
                filters = emptyList(),
                sort = SortCourses.BEST_MATCH
            )
        )


    override val playerId: String
        get() = islVideoUseCase.playerId
    override val corePlayerUiState: StateFlow<CorePlayerState>
        get() = islVideoUseCase.coreState
    val reattachVideo: MutableStateFlow<Int> = MutableStateFlow(0)

    fun triggerReattach(){
        reattachVideo.value += 1
    }

    override fun getPlayer(url: String): ExoPlayer {
        return islVideoUseCase.getPlayer(url)
    }

    override fun observePlaybackState() {
        viewModelScope.launch {
            islVideoUseCase.observePlaybackState()
        }
    }

    override fun onPlayPauseClick() {
        islVideoUseCase.onPlayPauseClick()
    }

    override fun toggleMute() {
        islVideoUseCase.toggleMute()
    }

    override fun rewind() {
        islVideoUseCase.rewind()
    }

    override fun pauseCompletely() {
        islVideoUseCase.pauseCompletely()
    }


    private val _bottomSheet = MutableStateFlow<ShortlistBottomSheetIdentifier>(ShortlistBottomSheetIdentifier.None)
    val bottomSheetState : StateFlow<ShortlistBottomSheetIdentifier> = _bottomSheet.asStateFlow()

    fun showBottom(identifier: ShortlistBottomSheetIdentifier){
        _bottomSheet.value = identifier
    }


    fun getCourses(){
        ioJob {
            shortlist.getShortlist()
        }
    }

    fun getRecommended() {
        ioJob {
            shortlist.getRecommended()
        }
    }

    fun onTabSelected(tab: ShortlistTabKey) {
        if (viewConfig.tabs.size <= 1) return
        if (_selectedTab.value == tab) return
        _selectedTab.value = tab
        when (tab) {
            ShortlistTabKey.RECOMMENDED -> getRecommended()
            ShortlistTabKey.SHORTLISTED -> getCourses()
        }
    }

    override fun actionFeedback(feedback: Feedback,courseId: Long){
        ioJob {
            shortlist.actionFeedback(feedback,courseId)
        }
    }

    override fun actionShortlist(addTOShortlist: Boolean, courseId: Long) {
        ioJob {
            shortlist.actionShortlist(addTOShortlist , courseId)
        }
    }

    val launchFeedback: MutableSharedFlow<Boolean> = MutableSharedFlow()

    val goToExplore: MutableSharedFlow<Unit> = MutableSharedFlow()

    override fun launchFeedback() {
        viewModelScope.launch {
            launchFeedback.emit(true)
        }
    }

    override fun goToExplore() {
        viewModelScope.launch {
            goToExplore.emit(Unit)
        }
    }

    fun updateFeedbackStatus(status: Boolean) {
        shortlist.updateFeedbackStatus(status)
    }

    fun onEvent(event: ShortlistEvent) {
        when(event) {
            is ShortlistEvent.ApplySortAndFilter -> {
                viewModelScope.launch {
                    shortlist.filterAndSort(
                        ShortlistFilterState(
                            sort = event.sort,
                            filters = event.filters.toList()
                        )
                    )
                }
            }

            ShortlistEvent.Clear -> {
                viewModelScope.launch {
                    //shortlist.clearAll()
                }
            }
        }
    }

    fun getCounsellorLockedStatus() : Boolean{
       return UserDataUtils.isCounsellorLocked()
    }

    fun getCounsellorData(): UserDashboardLeapPartnerModel? {
        val counsellor = CacheHelper.get("partners")
        val counsellorData = counsellor?.let {
            val list = counsellor as? List<UserDashboardLeapPartnerModel>
            list?.firstOrNull { it.typeOfPartner == UserType.COUNSELLOR }
        }
        return counsellorData
    }

    fun trackPageVisited() {
        analytics.shortlistPageVisited()
    }

